patch:
diff --git a/llvm/lib/Transforms/Utils/LoopUnrollAndJam.cpp b/llvm/lib/Transforms/Utils/LoopUnrollAndJam.cpp
index ca90bb65f570..5740a2b8d15e 100644
--- a/llvm/lib/Transforms/Utils/LoopUnrollAndJam.cpp
+++ b/llvm/lib/Transforms/Utils/LoopUnrollAndJam.cpp
@@ -69,6 +69,7 @@ typedef SmallPtrSet<BasicBlock *, 4> BasicBlockSet;
 // the loop
 static bool partitionLoopBlocks(Loop &L, BasicBlockSet &ForeBlocks,
                                 BasicBlockSet &AftBlocks, DominatorTree &DT) {
+  if (L.getSubLoops().empty()) return false;
   Loop *SubLoop = L.getSubLoops()[0];
   BasicBlock *SubLoopLatch = SubLoop->getLoopLatch();

@@ -221,6 +222,7 @@ llvm::UnrollAndJamLoop(Loop *L, unsigned Count, unsigned TripCount,
   // When we enter here we should have already checked that it is safe
   BasicBlock *Header = L->getHeader();
   assert(Header && "No header.");
+  if (L->getSubLoops().size() != 1) return LoopUnrollResult::Unmodified;
   assert(L->getSubLoops().size() == 1);
   Loop *SubLoop = *L->begin();

@@ -805,6 +807,7 @@ checkDependencies(Loop &Root, const BasicBlockSet &SubLoopBlocks,

 static bool isEligibleLoopForm(const Loop &Root) {
   // Root must have a child.
+  if (Root.isInvalid()) return false;
   if (Root.getSubLoops().size() != 1)
     return false;

@@ -847,6 +850,7 @@ static bool isEligibleLoopForm(const Loop &Root) {
       return false;
     }

+  if (L->getSubLoops().empty()) return false;
     L = L->getSubLoops()[0];
   } while (L);

@@ -854,6 +858,7 @@ static bool isEligibleLoopForm(const Loop &Root) {
 }

 static Loop *getInnerMostLoop(Loop *L) {
+  if (!L || L->getSubLoops().empty()) return L;;
   while (!L->getSubLoops().empty())
     L = L->getSubLoops()[0];
   return L;
@@ -965,6 +970,7 @@ bool llvm::isSafeToUnrollAndJam(Loop *L, ScalarEvolution &SE, DominatorTree &DT,
   BasicBlock *Header = L->getHeader();
   BasicBlock *Latch = L->getLoopLatch();
   BasicBlockSet AftBlocks = AftBlocksMap[L];
+  if (L->getSubLoops().empty()) return false;
   Loop *SubLoop = L->getSubLoops()[0];
   if (!processHeaderPhiOperands(
           Header, Latch, AftBlocks, [&AftBlocks, &SubLoop](Instruction *I) {
diff --git a/llvm/lib/Transforms/Utils/LoopUtils.cpp b/llvm/lib/Transforms/Utils/LoopUtils.cpp
index f57d95e7722d..96565958c248 100644
--- a/llvm/lib/Transforms/Utils/LoopUtils.cpp
+++ b/llvm/lib/Transforms/Utils/LoopUtils.cpp
@@ -1804,6 +1804,7 @@ void llvm::appendReversedLoopsToWorklist(
     PreOrderWorklist.push_back(RootL);
     do {
       Loop *L = PreOrderWorklist.pop_back_val();
+      if (!L || L->isInvalid()) continue;
       PreOrderWorklist.append(L->begin(), L->end());
       PreOrderLoops.push_back(L);
     } while (!PreOrderWorklist.empty());

